window.BILARA["dn09"] = window.BILARA["dn09"] || {};
window.BILARA["dn09"]["vi"] ={
  "dn9:0.1": "Trường Bộ Kinh 9 ",
  "dn9:0.2": "Kinh Poṭṭhapāda ",
  "dn9:1.0": "1. Câu chuyện về du sĩ Poṭṭhapāda ",
  "dn9:1.1": "Tôi nghe như vầy—",
  "dn9:1.2": "Một thời, Thế Tôn trú tại Sāvatthī, trong Jetavana, khu vườn của ông Anāthapiṇḍika. ",
  "dn9:1.3": "Lúc bấy giờ, du sĩ Poṭṭhapāda đang cư trú tại giảng đường của phái du sĩ Tindukācīra, ngôi nhà một mái trong vườn của Mallikā, cùng với một hội chúng du sĩ đông lớn gồm khoảng ba trăm du sĩ. ",
  "dn9:1.4": "Rồi Thế Tôn vào buổi sáng, sau khi đắp y, cầm bát và y, đi vào Sāvatthī để khất thực. ",
  "dn9:2.1": "Rồi Thế Tôn nghĩ rằng: ",
  "dn9:2.2": "“Còn quá sớm để đi khất thực trong thành Sāvatthī. ",
  "dn9:2.3": "Hay là ta đi đến giảng đường của phái du sĩ Tindukācīra, ngôi nhà một mái trong vườn của Mallikā, đến chỗ du sĩ Poṭṭhapāda.”",
  "dn9:2.4": "Rồi Thế Tôn đi đến giảng đường của phái du sĩ Tindukācīra, ngôi nhà một mái trong vườn của Mallikā. ",
  "dn9:3.1": "Lúc ấy, du sĩ Poṭṭhapāda đang ngồi cùng hội chúng du sĩ đông lớn ấy, giữa tiếng ồn ào, huyên náo, nói đủ thứ chuyện tạp thoại. ",
  "dn9:3.2": "Tức là: chuyện vua chúa, chuyện trộm cướp, chuyện quan lại, chuyện quân đội, chuyện sợ hãi, chuyện chiến tranh, chuyện ăn uống, chuyện đồ uống, chuyện y phục, chuyện chỗ nằm, chuyện vòng hoa, chuyện hương liệu, chuyện bà con, chuyện xe cộ, chuyện làng mạc, chuyện thị trấn, chuyện thành phố, chuyện xứ sở, chuyện đàn bà, chuyện anh hùng, chuyện đầu đường xó chợ, chuyện bến nước, chuyện người chết thuở trước, chuyện tạp nhạp, chuyện khởi nguyên thế giới, chuyện khởi nguyên biển cả, chuyện có hay không có đời sau, và những chuyện như thế. ",
  "dn9:4.1": "Du sĩ Poṭṭhapāda thấy Thế Tôn từ xa đang đi đến; ",
  "dn9:4.2": "thấy vậy, ông liền ngăn hội chúng của mình lại: ",
  "dn9:4.3": "“Xin chư vị hãy giữ yên lặng, đừng gây tiếng động. ",
  "dn9:4.4": "Sa-môn Gotama đang đến. ",
  "dn9:4.5": "Vị tôn giả ấy ưa sự yên lặng và tán thán sự yên lặng. ",
  "dn9:4.6": "Biết đâu khi thấy hội chúng yên lặng, ngài sẽ nghĩ nên đến gần.”",
  "dn9:4.7": "Khi nói vậy, các du sĩ ấy liền im lặng. ",
  "dn9:5.1": "Rồi Thế Tôn đi đến chỗ du sĩ Poṭṭhapāda. ",
  "dn9:5.2": "Rồi du sĩ Poṭṭhapāda bạch với Thế Tôn: ",
  "dn9:5.3": "“Xin mời Thế Tôn đến, bạch Ngài. ",
  "dn9:5.4": "Kính chào mừng Thế Tôn, bạch Ngài. ",
  "dn9:5.5": "Đã lâu lắm rồi Thế Tôn mới có dịp đến đây. ",
  "dn9:5.6": "Xin Thế Tôn ngồi, bạch Ngài, đây là chỗ ngồi đã được soạn sẵn.”",
  "dn9:5.7": "Thế Tôn ngồi xuống chỗ ngồi đã được soạn sẵn. ",
  "dn9:5.8": "Du sĩ Poṭṭhapāda cũng lấy một chỗ ngồi thấp khác rồi ngồi xuống một bên. ",
  "dn9:5.9": "Khi du sĩ Poṭṭhapāda đã ngồi xuống một bên, Thế Tôn nói với ông: ",
  "dn9:5.10": "“Này Poṭṭhapāda, hiện giờ các ông đang ngồi bàn luận chuyện gì, và câu chuyện gì đã bị bỏ dở giữa chừng?”",
  "dn9:6.0": "1.1. Bàn về sự diệt của các tưởng cao hơn ",
  "dn9:6.1": "Khi được nói vậy, du sĩ Poṭṭhapāda bạch với Thế Tôn: ",
  "dn9:6.2": "“Xin cứ để chuyện ấy lại, bạch Ngài, chuyện mà chúng con đang ngồi bàn lúc này. ",
  "dn9:6.3": "Câu chuyện ấy về sau Thế Tôn cũng không khó để nghe lại. ",
  "dn9:6.4": "Những ngày trước đây, bạch Ngài, các sa-môn, bà-la-môn thuộc nhiều giáo phái khác nhau, khi ngồi tụ họp trong giảng đường luận bàn, đã khởi lên cuộc thảo luận về sự diệt của các tưởng cao hơn: ",
  "dn9:6.5": "‘Này chư vị, sự diệt của các tưởng cao hơn xảy ra như thế nào?’ ",
  "dn9:6.6": "Trong đó, có người nói như vầy: ",
  "dn9:6.7": "‘Không có nhân, không có duyên, tưởng của con người sinh lên rồi diệt đi. ",
  "dn9:6.8": "Khi nào chúng sinh lên thì khi ấy người ấy là có tưởng. ",
  "dn9:6.9": "Khi nào chúng diệt đi thì khi ấy người ấy là không có tưởng.’ ",
  "dn9:6.10": "Đó là cách một số người trình bày về sự diệt của các tưởng cao hơn. ",
  "dn9:6.11": "Người khác lại nói như vầy: ",
  "dn9:6.12": "‘Này chư vị, điều ấy không phải như vậy. ",
  "dn9:6.13": "Vì tưởng chính là tự ngã của con người. ",
  "dn9:6.14": "Nó đến rồi nó đi. ",
  "dn9:6.15": "Khi nào nó đến thì khi ấy người ấy là có tưởng. ",
  "dn9:6.16": "Khi nào nó đi thì khi ấy người ấy là không có tưởng.’ ",
  "dn9:6.17": "Đó là cách một số người trình bày về sự diệt của các tưởng cao hơn. ",
  "dn9:6.18": "Người khác nữa lại nói như vầy: ",
  "dn9:6.19": "‘Này chư vị, điều ấy không phải như vậy. ",
  "dn9:6.20": "Vì có những sa-môn, bà-la-môn có thần lực lớn, uy lực lớn. ",
  "dn9:6.21": "Họ có thể kéo tưởng của người này đến hoặc kéo đi. ",
  "dn9:6.22": "Khi nào họ kéo đến thì khi ấy người ấy là có tưởng. ",
  "dn9:6.23": "Khi nào họ kéo đi thì khi ấy người ấy là không có tưởng.’ ",
  "dn9:6.24": "Đó là cách một số người trình bày về sự diệt của các tưởng cao hơn. ",
  "dn9:6.25": "Người khác nữa lại nói như vầy: ",
  "dn9:6.26": "‘Này chư vị, điều ấy không phải như vậy. ",
  "dn9:6.27": "Vì có những chư thiên có thần lực lớn, uy lực lớn. ",
  "dn9:6.28": "Các vị ấy có thể kéo tưởng của người này đến hoặc kéo đi. ",
  "dn9:6.29": "Khi nào các vị ấy kéo đến thì khi ấy người ấy là có tưởng. ",
  "dn9:6.30": "Khi nào các vị ấy kéo đi thì khi ấy người ấy là không có tưởng.’ ",
  "dn9:6.31": "Đó là cách một số người trình bày về sự diệt của các tưởng cao hơn. ",
  "dn9:6.32": "Khi ấy, bạch Ngài, con liền khởi niệm hướng về chính Thế Tôn: ",
  "dn9:6.33": "‘Ôi, chắc hẳn Thế Tôn, chắc hẳn bậc Thiện Thệ là người khéo léo trong những pháp này.’ ",
  "dn9:6.34": "Bạch Ngài, Thế Tôn là bậc thiện xảo, Thế Tôn hiểu rõ sự diệt của các tưởng cao hơn. ",
  "dn9:6.35": "Vậy, bạch Ngài, sự diệt của các tưởng cao hơn xảy ra như thế nào?”",
  "dn9:7.0": "1.2. Bàn về sự sinh khởi và diệt tận của tưởng có nhân duyên ",
  "dn9:7.1": "“Này Poṭṭhapāda, trong đó những sa-môn, bà-la-môn nào nói như vầy: ",
  "dn9:7.2": "‘Không có nhân, không có duyên, tưởng của con người sinh lên rồi diệt đi’, thì ngay từ đầu họ đã sai lầm. ",
  "dn9:7.3": "Vì sao vậy? ",
  "dn9:7.4": "Này Poṭṭhapāda, tưởng của con người sinh lên rồi diệt đi là có nhân, có duyên. ",
  "dn9:7.5": "Do một sự tu tập mà một loại tưởng sinh lên, do một sự tu tập mà một loại tưởng diệt đi. ",
  "dn9:7.6": "Và sự tu tập ấy là gì?” Thế Tôn nói. ",
  "dn9:7.7": "“Ở đây, này Poṭṭhapāda, Như Lai xuất hiện ở đời, là bậc A-la-hán, Chánh Đẳng Giác … ",
  "dn9:7.8": "Như vậy, này Poṭṭhapāda, vị tỳ-kheo thành tựu giới ",
  "dn9:8.1": "… ",
  "dn9:9.1": "Khi vị ấy thấy năm triền cái này đã được đoạn trừ nơi mình, hân hoan sinh khởi; do hân hoan nên hỷ sinh; người có hỷ thì thân được khinh an; thân khinh an thì cảm thọ lạc; người có lạc thì tâm được định tĩnh. ",
  "dn9:10.1": "Vị ấy ly dục, ly các pháp bất thiện, chứng và an trú sơ thiền, một trạng thái có tầm có tứ, có hỷ lạc do ly dục sinh. ",
  "dn9:10.2": "Nơi vị ấy, tưởng về dục trước đó diệt mất. ",
  "dn9:10.3": "Khi ấy có tưởng vi tế chân thật về hỷ lạc do ly dục sinh, và đúng vào lúc ấy vị ấy là người có tưởng vi tế chân thật về hỷ lạc do ly dục sinh. ",
  "dn9:10.4": "Như vậy cũng do một sự tu tập mà một loại tưởng sinh lên, do một sự tu tập mà một loại tưởng diệt đi. ",
  "dn9:10.5": "Đó là sự tu tập ấy,” Thế Tôn nói. ",
  "dn9:11.1": "“Lại nữa, này Poṭṭhapāda, vị tỳ-kheo do sự lắng dịu của tầm và tứ, chứng và an trú nhị thiền, một trạng thái nội tĩnh, nhất tâm, không tầm không tứ, có hỷ lạc do định sinh. ",
  "dn9:11.2": "Nơi vị ấy, tưởng vi tế chân thật về hỷ lạc do ly dục sinh trước đó diệt mất. ",
  "dn9:11.3": "Khi ấy có tưởng vi tế chân thật về hỷ lạc do định sinh, và đúng vào lúc ấy vị ấy là người có tưởng vi tế chân thật về hỷ lạc do định sinh. ",
  "dn9:11.4": "Như vậy cũng do một sự tu tập mà một loại tưởng sinh lên, do một sự tu tập mà một loại tưởng diệt đi. ",
  "dn9:11.5": "Đây cũng là sự tu tập ấy,” Thế Tôn nói. ",
  "dn9:12.1": "“Lại nữa, này Poṭṭhapāda, vị tỳ-kheo do ly hỷ, an trú xả, chánh niệm, tỉnh giác, thân cảm nhận lạc thọ, chứng và an trú tam thiền, trạng thái mà các bậc Thánh nói rằng: ‘Xả niệm, an trú lạc’. ",
  "dn9:12.2": "Nơi vị ấy, tưởng vi tế chân thật về hỷ lạc do định sinh trước đó diệt mất. ",
  "dn9:12.3": "Khi ấy có tưởng vi tế chân thật về lạc do xả, và đúng vào lúc ấy vị ấy là người có tưởng vi tế chân thật về lạc do xả. ",
  "dn9:12.4": "Như vậy cũng do một sự tu tập mà một loại tưởng sinh lên, do một sự tu tập mà một loại tưởng diệt đi. ",
  "dn9:12.5": "Đây cũng là sự tu tập ấy,” Thế Tôn nói. ",
  "dn9:13.1": "“Lại nữa, này Poṭṭhapāda, vị tỳ-kheo do đoạn trừ lạc, đoạn trừ khổ, do hỷ ưu đã diệt từ trước, chứng và an trú tứ thiền, trạng thái không khổ không lạc, thanh tịnh nhờ xả niệm. ",
  "dn9:13.2": "Nơi vị ấy, tưởng vi tế chân thật về lạc do xả trước đó diệt mất. ",
  "dn9:13.3": "Khi ấy có tưởng vi tế chân thật về không khổ không lạc, và đúng vào lúc ấy vị ấy là người có tưởng vi tế chân thật về không khổ không lạc. ",
  "dn9:13.4": "Như vậy cũng do một sự tu tập mà một loại tưởng sinh lên, do một sự tu tập mà một loại tưởng diệt đi. ",
  "dn9:13.5": "Đây cũng là sự tu tập ấy,” Thế Tôn nói. ",
  "dn9:14.1": "“Lại nữa, này Poṭṭhapāda, vị tỳ-kheo vượt qua hoàn toàn các tưởng về sắc, do sự biến mất của các tưởng về chướng ngại, không tác ý đến các tưởng sai khác, nghĩ rằng: ‘Hư không là vô biên’, chứng và an trú Không vô biên xứ. ",
  "dn9:14.2": "Nơi vị ấy, tưởng về sắc trước đó diệt mất. ",
  "dn9:14.3": "Khi ấy có tưởng vi tế chân thật về Không vô biên xứ, và đúng vào lúc ấy vị ấy là người có tưởng vi tế chân thật về Không vô biên xứ. ",
  "dn9:14.4": "Như vậy, do học tập mà một tưởng khởi lên, do học tập mà một tưởng diệt đi.",
  "dn9:14.5": "Đây cũng là sự học tập,” Thế Tôn nói.",
  "dn9:15.1": "“Lại nữa, này Poṭṭhapāda, vị tỳ-kheo vượt hẳn Không vô biên xứ, nghĩ rằng: ‘Thức là vô biên’, chứng và an trú trong Thức vô biên xứ.",
  "dn9:15.2": "Đối với vị ấy, cái tưởng chân thật vi tế thuộc Không vô biên xứ trước đó diệt đi.",
  "dn9:15.3": "Vào lúc ấy, cái tưởng chân thật vi tế thuộc Thức vô biên xứ hiện hữu; vào lúc ấy, vị ấy chính là người có tưởng chân thật vi tế thuộc Thức vô biên xứ.",
  "dn9:15.4": "Như vậy, do học tập mà một tưởng khởi lên, do học tập mà một tưởng diệt đi.",
  "dn9:15.5": "Đây cũng là sự học tập,” Thế Tôn nói.",
  "dn9:16.1": "“Lại nữa, này Poṭṭhapāda, vị tỳ-kheo vượt hẳn Thức vô biên xứ, nghĩ rằng: ‘Không có gì cả’, chứng và an trú trong Vô sở hữu xứ.",
  "dn9:16.2": "Đối với vị ấy, cái tưởng chân thật vi tế thuộc Thức vô biên xứ trước đó diệt đi.",
  "dn9:16.3": "Vào lúc ấy, cái tưởng chân thật vi tế thuộc Vô sở hữu xứ hiện hữu; vào lúc ấy, vị ấy chính là người có tưởng chân thật vi tế thuộc Vô sở hữu xứ.",
  "dn9:16.4": "Như vậy, do học tập mà một tưởng khởi lên, do học tập mà một tưởng diệt đi.",
  "dn9:16.5": "Đây cũng là sự học tập,” Thế Tôn nói.",
  "dn9:17.1": "“Khi nào, này Poṭṭhapāda, vị tỳ-kheo ở đây là người còn có tưởng, thì từ đó, lần lượt, vị ấy đạt đến đỉnh cao của tưởng.",
  "dn9:17.2": "Khi đã đứng ở đỉnh cao của tưởng, vị ấy nghĩ như sau:",
  "dn9:17.3": "‘Đối với ta, có tác ý thì xấu hơn, không tác ý thì tốt hơn.",
  "dn9:17.4": "Vì nếu ta tác ý, tạo tác, thì những tưởng này của ta sẽ diệt, và những tưởng thô hơn khác sẽ khởi lên;",
  "dn9:17.5": "vậy ta chớ có tác ý, chớ có tạo tác.’",
  "dn9:17.6": "Vị ấy không tác ý, cũng không tạo tác.",
  "dn9:17.7": "Do không tác ý, không tạo tác, những tưởng ấy diệt đi, và những tưởng thô hơn khác không khởi lên.",
  "dn9:17.8": "Vị ấy chứng đạt sự diệt.",
  "dn9:17.9": "Như vậy, này Poṭṭhapāda, là sự chứng nhập có tỉnh giác về sự diệt dần dần của các tưởng do tác thành.",
  "dn9:18.1": "Ông nghĩ thế nào, này Poṭṭhapāda,",
  "dn9:18.2": "trước đây ông đã từng nghe nói đến sự chứng nhập có tỉnh giác về sự diệt dần dần của các tưởng do tác thành như vậy chưa?”",
  "dn9:18.3": "“Thưa không, bạch Thế Tôn.",
  "dn9:18.4": "Nhưng nay, bạch Thế Tôn, con hiểu lời Thế Tôn dạy như sau:",
  "dn9:18.5": "‘Khi nào, này Poṭṭhapāda, vị tỳ-kheo ở đây là người còn có tưởng, thì từ đó, lần lượt, vị ấy đạt đến đỉnh cao của tưởng,",
  "dn9:18.6": "khi đã đứng ở đỉnh cao của tưởng, vị ấy nghĩ như sau:",
  "dn9:18.7": "“Đối với ta, có tác ý thì xấu hơn, không tác ý thì tốt hơn.",
  "dn9:18.8": "Vì nếu ta tác ý, tạo tác, thì những tưởng này của ta sẽ diệt, và những tưởng thô hơn khác sẽ khởi lên;",
  "dn9:18.9": "vậy ta chớ có tác ý, chớ có tạo tác.”",
  "dn9:18.10": "Vị ấy không tác ý, cũng không tạo tác; do không tác ý, không tạo tác, những tưởng ấy diệt đi, và những tưởng thô hơn khác không khởi lên.",
  "dn9:18.11": "Vị ấy chứng đạt sự diệt.",
  "dn9:18.12": "Như vậy, này Poṭṭhapāda, là sự chứng nhập có tỉnh giác về sự diệt dần dần của các tưởng do tác thành.’”",
  "dn9:18.13": "“Đúng vậy, này Poṭṭhapāda.”",
  "dn9:19.1": "“Bạch Thế Tôn, Thế Tôn chỉ thuyết một đỉnh cao của tưởng, hay thuyết nhiều đỉnh cao của tưởng?”",
  "dn9:19.2": "“Này Poṭṭhapāda, Ta thuyết cả một đỉnh cao của tưởng, và cũng thuyết nhiều đỉnh cao của tưởng.”",
  "dn9:19.3": "“Nhưng bạch Thế Tôn, như thế nào là Thế Tôn thuyết cả một đỉnh cao của tưởng, và cũng thuyết nhiều đỉnh cao của tưởng?”",
  "dn9:19.4": "“Này Poṭṭhapāda, tùy theo cách nào chứng đạt sự diệt, thì theo cách ấy Ta thuyết đỉnh cao của tưởng.",
  "dn9:19.5": "Như vậy, này Poṭṭhapāda, Ta thuyết cả một đỉnh cao của tưởng, và cũng thuyết nhiều đỉnh cao của tưởng.”",
  "dn9:20.1": "“Bạch Thế Tôn, phải chăng tưởng khởi lên trước, rồi sau mới đến trí; hay trí khởi lên trước, rồi sau mới đến tưởng; hay tưởng và trí cùng khởi lên, không trước không sau?”",
  "dn9:20.2": "“Này Poṭṭhapāda, tưởng khởi lên trước, rồi sau mới đến trí; và do tưởng khởi lên nên trí khởi lên.",
  "dn9:20.3": "Vị ấy biết như sau:",
  "dn9:20.4": "‘Do duyên này mà trí của ta khởi lên.’",
  "dn9:20.5": "Này Poṭṭhapāda, do phương thức này cần phải hiểu rằng—",
  "dn9:20.6": "tưởng khởi lên trước, rồi sau mới đến trí; và do tưởng khởi lên nên trí khởi lên.”",
  "dn9:21.0": "1.3. Luận về tưởng và ngã",
  "dn9:21.1": "“Bạch Thế Tôn, tưởng có phải là ngã của con người không, hay tưởng là một thứ khác còn ngã là một thứ khác?”",
  "dn9:21.2": "“Này Poṭṭhapāda, ông chấp nhận ngã là gì?”",
  "dn9:21.3": "“Bạch Thế Tôn, con chấp nhận ngã là thô trọng, có sắc, do bốn đại tạo thành, sống nhờ vật thực đoàn thực.”",
  "dn9:21.4": "“Này Poṭṭhapāda, nếu ngã của ông là thô trọng, có sắc, do bốn đại tạo thành, sống nhờ vật thực đoàn thực, thì trong trường hợp ấy, tưởng sẽ là một thứ khác, ngã sẽ là một thứ khác.",
  "dn9:21.5": "Này Poṭṭhapāda, chính do phương thức này mà cần phải hiểu rằng tưởng sẽ là một thứ khác, ngã sẽ là một thứ khác.",
  "dn9:21.6": "Ngã thô trọng ấy của ông vẫn tồn tại, có sắc, do bốn đại tạo thành, sống nhờ vật thực đoàn thực; nhưng nơi người ấy, những tưởng này khởi lên và những tưởng khác diệt đi.",
  "dn9:21.7": "Chính do phương thức này, này Poṭṭhapāda, cần phải hiểu rằng tưởng sẽ là một thứ khác, ngã sẽ là một thứ khác.”",
  "dn9:22.1": "“Bạch Thế Tôn, con chấp nhận ngã là do ý tạo, đầy đủ mọi chi phần, không thiếu một căn nào.”",
  "dn9:22.2": "“Này Poṭṭhapāda, nếu ngã của ông là do ý tạo, đầy đủ mọi chi phần, không thiếu một căn nào, thì ngay trong trường hợp ấy, tưởng sẽ là một thứ khác, ngã sẽ là một thứ khác.",
  "dn9:22.3": "Này Poṭṭhapāda, chính do phương thức này mà cần phải hiểu rằng tưởng sẽ là một thứ khác, ngã sẽ là một thứ khác.",
  "dn9:22.4": "Ngã do ý tạo ấy của ông vẫn tồn tại, đầy đủ mọi chi phần, không thiếu một căn nào; nhưng nơi người ấy, những tưởng này khởi lên và những tưởng khác diệt đi.",
  "dn9:22.5": "Cũng do phương thức này, này Poṭṭhapāda, cần phải hiểu rằng tưởng sẽ là một thứ khác, ngã sẽ là một thứ khác.”",
  "dn9:23.1": "“Bạch Thế Tôn, con chấp nhận ngã là vô sắc, do tưởng tạo thành.”",
  "dn9:23.2": "“Này Poṭṭhapāda, nếu ngã của ông là vô sắc, do tưởng tạo thành, thì ngay trong trường hợp ấy, tưởng sẽ là một thứ khác, ngã sẽ là một thứ khác.",
  "dn9:23.3": "Này Poṭṭhapāda, chính do phương thức này mà cần phải hiểu rằng tưởng sẽ là một thứ khác, ngã sẽ là một thứ khác.",
  "dn9:23.4": "Ngã vô sắc ấy của ông vẫn tồn tại, do tưởng tạo thành; nhưng nơi người ấy, những tưởng này khởi lên và những tưởng khác diệt đi.",
  "dn9:23.5": "Cũng do phương thức này, này Poṭṭhapāda, cần phải hiểu rằng tưởng sẽ là một thứ khác, ngã sẽ là một thứ khác.”",
  "dn9:24.1": "“Nhưng bạch Thế Tôn, con có thể biết được chăng:",
  "dn9:24.2": "‘tưởng là ngã của con người’ hay ‘tưởng là một thứ khác, ngã là một thứ khác’?”",
  "dn9:24.3": "“Này Poṭṭhapāda, điều ấy khó để ông biết được, vì ông có kiến giải khác, chấp nhận khác, ưa thích khác, thực hành khác, theo thầy khác:",
  "dn9:24.4": "‘tưởng là ngã của con người’ hay ‘tưởng là một thứ khác, ngã là một thứ khác’.”",
  "dn9:25.1": "“Nếu điều ấy khó để con biết được, bạch Thế Tôn, vì con có kiến giải khác, chấp nhận khác, ưa thích khác, thực hành khác, theo thầy khác:",
  "dn9:25.2": "‘tưởng là ngã của con người’ hay ‘tưởng là một thứ khác, ngã là một thứ khác’;",
  "dn9:25.3": "vậy thì, bạch Thế Tôn, ‘thế giới là thường còn, đây mới là chân thật, còn điều khác là hư vọng’ chăng?”",
  "dn9:25.4": "“Này Poṭṭhapāda, điều ấy Ta không trả lời:",
  "dn9:25.5": "‘thế giới là thường còn, đây mới là chân thật, còn điều khác là hư vọng’.”",
  "dn9:26.1": "“Vậy thì, bạch Thế Tôn, ‘thế giới là không thường còn, đây mới là chân thật, còn điều khác là hư vọng’ chăng?”",
  "dn9:26.2": "“Này Poṭṭhapāda, điều ấy Ta cũng không trả lời:",
  "dn9:26.3": "‘thế giới là không thường còn, đây mới là chân thật, còn điều khác là hư vọng’.”",
  "dn9:27.1": "“Vậy thì, bạch Thế Tôn, ‘thế giới là hữu biên …",
  "dn9:27.2": "‘thế giới là vô biên …",
  "dn9:27.3": "‘mạng sống ấy chính là thân này …",
  "dn9:27.4": "‘mạng sống là một thứ, thân là một thứ khác …",
  "dn9:27.5": "‘Như Lai còn tồn tại sau khi chết …",
  "dn9:27.6": "‘Như Lai không còn tồn tại sau khi chết …",
  "dn9:27.7": "‘Như Lai vừa còn tồn tại vừa không còn tồn tại sau khi chết …",
  "dn9:27.8": "‘Như Lai sau khi chết không phải còn tồn tại cũng không phải không còn tồn tại, đây mới là chân thật, còn điều khác là hư vọng’ chăng?”",
  "dn9:27.9": "“Này Poṭṭhapāda, điều ấy Ta cũng không trả lời:",
  "dn9:27.10": "‘Như Lai sau khi chết không phải còn tồn tại cũng không phải không còn tồn tại, đây mới là chân thật, còn điều khác là hư vọng’.”",
  "dn9:28.1": "“Nhưng vì sao, bạch Thế Tôn, Thế Tôn không trả lời điều ấy?”",
  "dn9:28.2": "“Này Poṭṭhapāda, vì điều ấy không liên hệ đến lợi ích, không liên hệ đến pháp, không thuộc căn bản phạm hạnh, không đưa đến yếm ly, không đưa đến ly tham, không đưa đến diệt, không đưa đến an tịnh, không đưa đến thắng trí, không đưa đến giác ngộ, không đưa đến Niết-bàn,",
  "dn9:28.3": "nên Ta không trả lời điều ấy.”",
  "dn9:29.1": "“Vậy thì, bạch Thế Tôn, điều gì được Thế Tôn trả lời?”",
  "dn9:29.2": "“Này Poṭṭhapāda, ‘đây là khổ’ là điều Ta đã trả lời. ‘Đây là nguyên nhân của khổ’ là điều Ta đã trả lời. ‘Đây là sự diệt khổ’ là điều Ta đã trả lời. ‘Đây là con đường đưa đến sự diệt khổ’ là điều Ta đã trả lời.”",
  "dn9:30.1": "“Nhưng vì sao, bạch Thế Tôn, điều ấy được Thế Tôn trả lời?”",
  "dn9:30.2": "“Này Poṭṭhapāda, vì điều ấy liên hệ đến lợi ích, liên hệ đến pháp, thuộc căn bản phạm hạnh, đưa đến yếm ly, ly tham, diệt, an tịnh, thắng trí, giác ngộ, Niết-bàn;",
  "dn9:30.3": "nên Ta đã trả lời điều ấy.”",
  "dn9:30.4": "“Đúng vậy, bạch Thế Tôn, đúng vậy, bạch Thiện Thệ.",
  "dn9:30.5": "Bạch Thế Tôn, nay xin Thế Tôn tùy thời.”",
  "dn9:30.6": "Rồi Thế Tôn từ chỗ ngồi đứng dậy và ra đi.",
  "dn9:31.1": "Bấy giờ, các du sĩ ấy, sau khi Thế Tôn vừa đi không bao lâu, liền từ mọi phía dùng lời nói công kích, châm chọc du sĩ Poṭṭhapāda:",
  "dn9:31.2": "“Thật vậy, tôn giả Poṭṭhapāda này, bất cứ điều gì Sa-môn Gotama nói, thì ông ta đều tán đồng đúng điều ấy:",
  "dn9:31.3": "‘Đúng vậy, bạch Thế Tôn, đúng vậy, bạch Thiện Thệ.’",
  "dn9:31.4": "Nhưng chúng ta chẳng hiểu được một pháp nào mà Sa-môn Gotama đã giảng một cách dứt khoát cả:",
  "dn9:31.5": "‘Thế giới là thường còn’ hay ‘thế giới là không thường còn’, hay ‘thế giới là hữu biên’, hay ‘thế giới là vô biên’, hay ‘mạng sống ấy chính là thân thể ấy’, hay ‘mạng sống là một, thân thể là một khác’, hay ‘Như Lai còn tồn tại sau khi chết’, hay ‘Như Lai không còn tồn tại sau khi chết’, hay ‘Như Lai vừa còn tồn tại vừa không còn tồn tại sau khi chết’, hay ‘Như Lai không phải còn tồn tại cũng không phải không còn tồn tại sau khi chết’.”",
  "dn9:31.6": "Khi được nói vậy, du sĩ Poṭṭhapāda nói với các du sĩ ấy như sau:",
  "dn9:31.7": "“Thưa chư hiền, tôi cũng không biết có một pháp nào được Sa-môn Gotama thuyết giảng một chiều rằng:",
  "dn9:31.8": "‘Thế giới là thường còn’ hay ‘thế giới là không thường còn’ …",
  "dn9:31.9": "hay ‘Như Lai không phải còn tồn tại cũng không phải không còn tồn tại sau khi chết’;",
  "dn9:31.10": "nhưng Sa-môn Gotama trình bày con đường chân thật, đúng như thực, là sự an trú của pháp, tính tất định của pháp.",
  "dn9:31.11": "Và khi Sa-môn Gotama trình bày con đường chân thật, đúng như thực, là sự an trú của pháp, tính tất định của pháp, thì làm sao một người có trí như tôi lại không tán thán lời khéo nói của Sa-môn Gotama như là lời khéo nói được?”",
  "dn9:32.0": "2. Chuyện Citta Hatthisāriputta và Poṭṭhapāda",
  "dn9:32.1": "Rồi sau hai ba ngày, Citta Hatthisāriputta và du sĩ Poṭṭhapāda đi đến chỗ Thế Tôn; sau khi đến, Citta Hatthisāriputta đảnh lễ Thế Tôn rồi ngồi xuống một bên.",
  "dn9:32.2": "Còn du sĩ Poṭṭhapāda thì chào hỏi thân thiện với Thế Tôn. Sau khi nói những lời thăm hỏi xã giao, đáng ghi nhớ, ông ngồi xuống một bên.",
  "dn9:32.3": "Khi đã ngồi xuống một bên, du sĩ Poṭṭhapāda bạch Thế Tôn như sau:",
  "dn9:32.4": "“Bạch Thế Tôn, khi Thế Tôn vừa mới đi không bao lâu, các du sĩ ấy đã vây quanh tôi, dùng lời nói mà dội nước lên tôi, làm tôi ngập chìm trong lời lẽ:",
  "dn9:32.5": "‘Tôn giả Poṭṭhapāda này quả thật là như vậy: Sa-môn Gotama nói điều gì thì ông ta cũng tán đồng đúng điều ấy:",
  "dn9:32.6": "“Đúng vậy, bạch Thế Tôn, đúng vậy, bạch Thiện Thệ.”",
  "dn9:32.7": "Nhưng chúng tôi không biết có một pháp nào được Sa-môn Gotama thuyết giảng một chiều rằng:",
  "dn9:32.8": "“Thế giới là thường còn”, hay “thế giới là không thường còn”, hay “thế giới là hữu biên”, hay “thế giới là vô biên”, hay “mạng sống ấy chính là thân thể ấy”, hay “mạng sống là một, thân thể là một khác”, hay “Như Lai còn tồn tại sau khi chết”, hay “Như Lai không còn tồn tại sau khi chết”, hay “Như Lai vừa còn tồn tại vừa không còn tồn tại sau khi chết”, hay “Như Lai không phải còn tồn tại cũng không phải không còn tồn tại sau khi chết”.’",
  "dn9:32.9": "Bạch Thế Tôn, khi được nói như vậy, con đã nói với các du sĩ ấy như sau:",
  "dn9:32.10": "‘Thưa chư hiền, tôi cũng không biết có một pháp nào được Sa-môn Gotama thuyết giảng một chiều rằng:",
  "dn9:32.11": "“Thế giới là thường còn”, hay “thế giới là không thường còn” …",
  "dn9:32.12": "hay “Như Lai không phải còn tồn tại cũng không phải không còn tồn tại sau khi chết”;",
  "dn9:32.13": "nhưng Sa-môn Gotama trình bày con đường chân thật, đúng như thực, là sự an trú của pháp, tính tất định của pháp.",
  "dn9:32.14": "Và khi Sa-môn Gotama trình bày con đường chân thật, đúng như thực, là sự an trú của pháp, tính tất định của pháp, thì làm sao một người có trí như tôi lại không tán thán lời khéo nói của Sa-môn Gotama như là lời khéo nói được?’”",
  "dn9:33.1": "“Này Poṭṭhapāda, tất cả các du sĩ ấy đều mù, không có mắt;",
  "dn9:33.2": "chỉ riêng ông là người có mắt trong số họ.",
  "dn9:33.3": "Này Poṭṭhapāda, quả thật có những pháp đã được Ta thuyết giảng và xác định một chiều;",
  "dn9:33.4": "cũng có những pháp đã được Ta thuyết giảng và xác định không một chiều.",
  "dn9:33.5": "Và này Poṭṭhapāda, những pháp nào là những pháp đã được Ta thuyết giảng và xác định không một chiều?",
  "dn9:33.6": "Này Poṭṭhapāda, ‘thế giới là thường còn’ là pháp đã được Ta thuyết giảng và xác định không một chiều;",
  "dn9:33.7": "này Poṭṭhapāda, ‘thế giới là không thường còn’ là pháp đã được Ta thuyết giảng và xác định không một chiều;",
  "dn9:33.8": "này Poṭṭhapāda, ‘thế giới là hữu biên’ …",
  "dn9:33.9": "này Poṭṭhapāda, ‘thế giới là vô biên’ …",
  "dn9:33.10": "này Poṭṭhapāda, ‘mạng sống ấy chính là thân thể ấy’ …",
  "dn9:33.11": "này Poṭṭhapāda, ‘mạng sống là một, thân thể là một khác’ …",
  "dn9:33.12": "này Poṭṭhapāda, ‘Như Lai còn tồn tại sau khi chết’ …",
  "dn9:33.13": "này Poṭṭhapāda, ‘Như Lai không còn tồn tại sau khi chết’ …",
  "dn9:33.14": "này Poṭṭhapāda, ‘Như Lai vừa còn tồn tại vừa không còn tồn tại sau khi chết’ …",
  "dn9:33.15": "này Poṭṭhapāda, ‘Như Lai không phải còn tồn tại cũng không phải không còn tồn tại sau khi chết’ là pháp đã được Ta thuyết giảng và xác định không một chiều.",
  "dn9:33.16": "Và này Poṭṭhapāda, vì sao những pháp ấy đã được Ta thuyết giảng và xác định không một chiều?",
  "dn9:33.17": "Vì này Poṭṭhapāda, chúng không liên hệ đến mục đích, không liên hệ đến pháp, không thuộc căn bản phạm hạnh, không đưa đến nhàm chán, không đưa đến ly tham, không đưa đến đoạn diệt, không đưa đến an tịnh, không đưa đến thắng trí, không đưa đến giác ngộ, không đưa đến Niết-bàn.",
  "dn9:33.18": "Vì vậy, những pháp ấy đã được Ta thuyết giảng và xác định không một chiều.",
  "dn9:33.19.0": "2.1. Những pháp một chiều",
  "dn9:33.20": "Và này Poṭṭhapāda, những pháp nào là những pháp đã được Ta thuyết giảng và xác định một chiều?",
  "dn9:33.21": "Này Poṭṭhapāda, ‘đây là khổ’ là pháp đã được Ta thuyết giảng và xác định một chiều.",
  "dn9:33.22": "Này Poṭṭhapāda, ‘đây là nguyên nhân của khổ’ là pháp đã được Ta thuyết giảng và xác định một chiều.",
  "dn9:33.23": "Này Poṭṭhapāda, ‘đây là sự diệt khổ’ là pháp đã được Ta thuyết giảng và xác định một chiều.",
  "dn9:33.24": "Này Poṭṭhapāda, ‘đây là con đường đưa đến sự diệt khổ’ là pháp đã được Ta thuyết giảng và xác định một chiều.",
  "dn9:33.25": "Và này Poṭṭhapāda, vì sao những pháp ấy đã được Ta thuyết giảng và xác định một chiều?",
  "dn9:33.26": "Vì này Poṭṭhapāda, chúng liên hệ đến mục đích, liên hệ đến pháp, thuộc căn bản phạm hạnh, đưa đến nhàm chán, ly tham, đoạn diệt, an tịnh, thắng trí, giác ngộ, Niết-bàn.",
  "dn9:33.27": "Vì vậy, những pháp ấy đã được Ta thuyết giảng và xác định một chiều.",
  "dn9:34.1": "Này Poṭṭhapāda, có một số sa-môn, bà-la-môn chủ trương như vầy, có kiến giải như vầy:",
  "dn9:34.2": "‘Tự ngã sau khi chết là hoàn toàn an lạc, không bệnh.’",
  "dn9:34.3": "Ta đến gặp họ và nói như sau:",
  "dn9:34.4": "‘Có thật chăng, chư tôn giả chủ trương như vầy, có kiến giải như vầy:",
  "dn9:34.5": "“Tự ngã sau khi chết là hoàn toàn an lạc, không bệnh”?’",
  "dn9:34.6": "Nếu khi được Ta hỏi như vậy, họ thừa nhận rằng ‘phải’.",
  "dn9:34.7": "Thì Ta nói như sau:",
  "dn9:34.8": "‘Vậy chư tôn giả có biết, có thấy và an trú trong một thế giới hoàn toàn an lạc chăng?’",
  "dn9:34.9": "Khi được hỏi vậy, họ nói ‘không’.",
  "dn9:34.10": "Thì Ta nói như sau:",
  "dn9:34.11": "‘Vậy chư tôn giả có nhận biết tự ngã của mình là hoàn toàn an lạc trong một đêm, hay một ngày, hay nửa đêm, hay nửa ngày chăng?’",
  "dn9:34.12": "Khi được hỏi vậy, họ nói ‘không’.",
  "dn9:34.13": "Thì Ta nói như sau:",
  "dn9:34.14": "‘Vậy chư tôn giả có biết rằng:",
  "dn9:34.15": "“Đây là con đường, đây là lối thực hành để chứng ngộ thế giới hoàn toàn an lạc” chăng?’",
  "dn9:34.16": "Khi được hỏi vậy, họ nói ‘không’.",
  "dn9:34.17": "Thì Ta nói như sau:",
  "dn9:34.18": "‘Vậy chư tôn giả có nghe tiếng nói của những chư thiên đã sinh vào thế giới hoàn toàn an lạc, khi họ nói rằng:",
  "dn9:34.19": "“Này các hiền giả, các vị đã thực hành tốt, này các hiền giả, các vị đã thực hành ngay thẳng để chứng ngộ thế giới hoàn toàn an lạc;",
  "dn9:34.20": "vì chính chúng tôi cũng do thực hành như vậy mà được sinh vào thế giới hoàn toàn an lạc” chăng?’",
  "dn9:34.21": "Khi được hỏi vậy, họ nói ‘không’.",
  "dn9:34.22": "Này Poṭṭhapāda, ông nghĩ sao,",
  "dn9:34.23": "trong trường hợp như vậy, lời nói của các sa-môn, bà-la-môn ấy chẳng phải là không có căn cứ sao?”",
  "dn9:34.24": "“Thưa Thế Tôn, đúng vậy, trong trường hợp như vậy, lời nói của các sa-môn, bà-la-môn ấy là không có căn cứ.”",
  "dn9:35.1": "“Ví như, này Poṭṭhapāda, có người nói như vầy:",
  "dn9:35.2": "‘Ta yêu thích, ta khao khát người đẹp nhất trong xứ này.’",
  "dn9:35.3": "Người ta có thể nói với người ấy như sau:",
  "dn9:35.4": "‘Này anh kia, người đẹp nhất trong xứ mà anh yêu thích, khao khát ấy, anh có biết nàng là người thuộc giai cấp sát-đế-lỵ, hay bà-la-môn, hay phệ-xá, hay thủ-đà chăng?’",
  "dn9:35.5": "Khi được hỏi vậy, người ấy sẽ nói ‘không’.",
  "dn9:35.6": "Người ta có thể nói với người ấy như sau:",
  "dn9:35.7": "‘Này anh kia, người đẹp nhất trong xứ mà anh yêu thích, khao khát ấy, anh có biết nàng tên gì, họ gì, cao hay thấp, hay tầm thước, da đen hay da ngăm, hay da màu vàng sẫm, ở làng nào, thị trấn nào, hay thành phố nào chăng?’",
  "dn9:35.8": "Khi được hỏi vậy, người ấy sẽ nói ‘không’.",
  "dn9:35.9": "Người ta có thể nói với người ấy như sau:",
  "dn9:35.10": "‘Này anh kia, cái mà anh không biết, không thấy, vậy mà anh lại yêu thích, khao khát sao?’",
  "dn9:35.11": "Khi được hỏi vậy, người ấy sẽ nói ‘phải’.",
  "dn9:35.12": "Này Poṭṭhapāda, ông nghĩ sao,",
  "dn9:35.13": "trong trường hợp như vậy, lời nói của người ấy chẳng phải là không có căn cứ sao?”",
  "dn9:35.14": "“Thưa Thế Tôn, đúng vậy, trong trường hợp như vậy, lời nói của người ấy là không có căn cứ.”",
  "dn9:36.1": "“Cũng vậy, này Poṭṭhapāda, những sa-môn, bà-la-môn nào chủ trương như vầy, có kiến giải như vầy:",
  "dn9:36.2": "‘Tự ngã sau khi chết là hoàn toàn an lạc, không bệnh.’",
  "dn9:36.3": "Ta đến gặp họ và nói như sau:",
  "dn9:36.4": "‘Có thật chăng, chư tôn giả chủ trương như vầy, có kiến giải như vầy:",
  "dn9:36.5": "“Tự ngã sau khi chết là hoàn toàn an lạc, không bệnh”?’",
  "dn9:36.6": "Nếu khi được Ta hỏi như vậy, họ thừa nhận rằng ‘phải’.",
  "dn9:36.7": "Thì Ta nói như sau:",
  "dn9:36.8": "‘Vậy chư tôn giả có biết, có thấy và an trú trong một thế giới hoàn toàn an lạc chăng?’",
  "dn9:36.9": "Khi được hỏi vậy, họ nói ‘không’.",
  "dn9:36.10": "Thì Ta nói như sau:",
  "dn9:36.11": "‘Vậy chư tôn giả có nhận biết tự ngã của mình là hoàn toàn an lạc trong một đêm, hay một ngày, hay nửa đêm, hay nửa ngày chăng?’",
  "dn9:36.12": "Khi được hỏi vậy, họ nói ‘không’.",
  "dn9:36.13": "Thì Ta nói như sau:",
  "dn9:36.14": "‘Nhưng này chư tôn giả, các vị có biết: ",
  "dn9:36.15": "“đây là con đường, đây là lối thực hành để chứng ngộ thế giới hoàn toàn an lạc”’ chăng? ",
  "dn9:36.16": "Khi được hỏi vậy, họ đáp: ‘Không’. ",
  "dn9:36.17": "Khi ấy ta nói như vầy: ",
  "dn9:36.18": "‘Nhưng này chư tôn giả, các vị có nghe tiếng nói của những chư thiên đã sinh vào thế giới hoàn toàn an lạc ấy, khi họ đang nói rằng: ",
  "dn9:36.19": "“Các hiền giả đã thực hành tốt, các hiền giả đã thực hành ngay thẳng, để chứng ngộ thế giới hoàn toàn an lạc; ",
  "dn9:36.20": "vì chính chúng tôi cũng do thực hành như vậy mà đã sinh vào thế giới hoàn toàn an lạc”’ chăng? ",
  "dn9:36.21": "Khi được hỏi vậy, họ đáp: ‘Không’. ",
  "dn9:36.22": "Ông nghĩ sao, này Poṭṭhapāda, trong trường hợp như vậy, lời nói của các sa-môn, bà-la-môn ấy chẳng phải là không có căn cứ sao?’",
  "dn9:36.23": "‘Thưa Thế Tôn, đúng vậy, trong trường hợp như vậy, lời nói của các sa-môn, bà-la-môn ấy là không có căn cứ.’ ",
  "dn9:37.1": "‘Ví như, này Poṭṭhapāda, có người làm một cái thang để leo lên lầu. ",
  "dn9:37.2": "Người ta có thể nói với người ấy như vầy: ",
  "dn9:37.3": "“Này anh kia, cái lầu mà anh làm thang để leo lên đó, anh có biết nó ở phương đông, hay phương nam, hay phương tây, hay phương bắc; cao, thấp hay vừa phải không?” ",
  "dn9:37.4": "Khi được hỏi vậy, người ấy đáp: ‘Không’. ",
  "dn9:37.5": "Người ta có thể nói với người ấy như vầy: ",
  "dn9:37.6": "“Này anh kia, anh đang làm thang để leo lên một cái lầu mà anh không biết, không thấy sao?” ",
  "dn9:37.7": "Khi được hỏi vậy, người ấy đáp: ‘Vâng’. ",
  "dn9:37.8": "Ông nghĩ sao, này Poṭṭhapāda, ",
  "dn9:37.9": "trong trường hợp như vậy, lời nói của người ấy chẳng phải là không có căn cứ sao?’",
  "dn9:37.10": "‘Thưa Thế Tôn, đúng vậy, trong trường hợp như vậy, lời nói của người ấy là không có căn cứ.’ ",
  "dn9:38.1": "‘Cũng vậy, này Poṭṭhapāda, những sa-môn, bà-la-môn nào chủ trương như vầy, có kiến chấp như vầy: ",
  "dn9:38.2": "“Tự ngã sau khi chết là hoàn toàn an lạc, không bệnh hoạn.” ",
  "dn9:38.3": "Ta đến gặp họ rồi nói như vầy: ",
  "dn9:38.4": "“Có thật chăng, này chư tôn giả, các vị chủ trương như vậy, có kiến chấp như vậy: ",
  "dn9:38.5": "‘Tự ngã sau khi chết là hoàn toàn an lạc, không bệnh hoạn’?” ",
  "dn9:38.6": "Nếu khi được ta hỏi như vậy, họ thừa nhận: ‘Vâng’. ",
  "dn9:38.7": "Khi ấy ta nói như vầy: ",
  "dn9:38.8": "‘Nhưng này chư tôn giả, các vị có sống biết và thấy thế giới hoàn toàn an lạc ấy chăng?’ ",
  "dn9:38.9": "Khi được hỏi vậy, họ đáp: ‘Không’. ",
  "dn9:38.10": "Khi ấy ta nói như vầy: ",
  "dn9:38.11": "‘Nhưng này chư tôn giả, các vị có tự biết mình là hoàn toàn an lạc trong một đêm, hay một ngày, hay nửa đêm, hay nửa ngày chăng?’ ",
  "dn9:38.12": "Khi được hỏi vậy, họ đáp: ‘Không’. ",
  "dn9:38.13": "Khi ấy ta nói như vầy: ",
  "dn9:38.14": "‘Nhưng này chư tôn giả, các vị có biết đây là con đường, đây là lối thực hành để chứng ngộ thế giới hoàn toàn an lạc chăng?’ ",
  "dn9:38.15": "Khi được hỏi vậy, họ đáp: ‘Không’. ",
  "dn9:38.16": "Khi ấy ta nói như vầy: ",
  "dn9:38.17": "‘Nhưng này chư tôn giả, các vị có nghe tiếng nói của những chư thiên đã sinh vào thế giới hoàn toàn an lạc ấy, khi các vị ấy đang nói rằng: ",
  "dn9:38.18": "“Các hiền giả đã thực hành tốt, các hiền giả đã thực hành ngay thẳng, để chứng ngộ thế giới hoàn toàn an lạc; ",
  "dn9:38.19": "vì chính chúng tôi cũng do thực hành như vậy mà đã sinh vào thế giới hoàn toàn an lạc”’ chăng? ",
  "dn9:38.20": "Khi được hỏi vậy, họ đáp: ‘Không’. ",
  "dn9:38.21": "Ông nghĩ sao, này Poṭṭhapāda, trong trường hợp như vậy, lời nói của các sa-môn, bà-la-môn ấy chẳng phải là không có căn cứ sao?’",
  "dn9:38.22": "‘Thưa Thế Tôn, đúng vậy, trong trường hợp như vậy, lời nói của các sa-môn, bà-la-môn ấy là không có căn cứ.’ ",
  "dn9:39.0": "2.2. Ba sự đạt được tự ngã ",
  "dn9:39.1": "‘Này Poṭṭhapāda, có ba sự đạt được tự ngã: ",
  "dn9:39.2": "sự đạt được tự ngã thô, sự đạt được tự ngã do ý tạo, và sự đạt được tự ngã vô sắc. ",
  "dn9:39.3": "Và này Poṭṭhapāda, thế nào là sự đạt được tự ngã thô? ",
  "dn9:39.4": "Có sắc, do bốn đại tạo thành, sống nhờ vật thực đoàn thực; đó là sự đạt được tự ngã thô. ",
  "dn9:39.5": "Thế nào là sự đạt được tự ngã do ý tạo? ",
  "dn9:39.6": "Có sắc, do ý tạo, đầy đủ các chi phần, không thiếu một căn nào; đó là sự đạt được tự ngã do ý tạo. ",
  "dn9:39.7": "Thế nào là sự đạt được tự ngã vô sắc? ",
  "dn9:39.8": "Không có sắc, do tưởng tạo thành; đó là sự đạt được tự ngã vô sắc. ",
  "dn9:40.1": "Này Poṭṭhapāda, đối với sự đạt được tự ngã thô, ta cũng thuyết pháp để từ bỏ nó: ",
  "dn9:40.2": "‘để cho nơi các ông, khi thực hành đúng theo đó, các pháp nhiễm ô sẽ được đoạn trừ, các pháp thanh tịnh sẽ được tăng trưởng, và các ông sẽ ngay trong hiện tại, tự mình với thắng trí chứng ngộ, thành tựu và an trú trong sự viên mãn và quảng đại của trí tuệ.’ ",
  "dn9:40.3": "Nhưng này Poṭṭhapāda, có thể các ông nghĩ như vầy: ",
  "dn9:40.4": "‘Các pháp nhiễm ô sẽ được đoạn trừ, các pháp thanh tịnh sẽ được tăng trưởng, và người ấy sẽ ngay trong hiện tại, tự mình với thắng trí chứng ngộ, thành tựu và an trú trong sự viên mãn và quảng đại của trí tuệ; nhưng đời sống ấy hẳn là khổ.’ ",
  "dn9:40.5": "Này Poṭṭhapāda, không nên thấy như vậy. ",
  "dn9:40.6": "Các pháp nhiễm ô sẽ được đoạn trừ, các pháp thanh tịnh sẽ được tăng trưởng, và người ấy sẽ ngay trong hiện tại, tự mình với thắng trí chứng ngộ, thành tựu và an trú trong sự viên mãn và quảng đại của trí tuệ; và sẽ có hân hoan, hỷ, khinh an, chánh niệm, tỉnh giác, và đời sống an lạc. ",
  "dn9:41.1": "Này Poṭṭhapāda, đối với sự đạt được tự ngã do ý tạo, ta cũng thuyết pháp để từ bỏ nó: ",
  "dn9:41.2": "‘để cho nơi các ông, khi thực hành đúng theo đó, các pháp nhiễm ô sẽ được đoạn trừ, các pháp thanh tịnh sẽ được tăng trưởng, và các ông sẽ ngay trong hiện tại, tự mình với thắng trí chứng ngộ, thành tựu và an trú trong sự viên mãn và quảng đại của trí tuệ.’ ",
  "dn9:41.3": "Nhưng này Poṭṭhapāda, có thể các ông nghĩ như vầy: ",
  "dn9:41.4": "‘Các pháp nhiễm ô sẽ được đoạn trừ, các pháp thanh tịnh sẽ được tăng trưởng, và người ấy sẽ ngay trong hiện tại, tự mình với thắng trí chứng ngộ, thành tựu và an trú trong sự viên mãn và quảng đại của trí tuệ; nhưng đời sống ấy hẳn là khổ.’ ",
  "dn9:41.5": "Này Poṭṭhapāda, không nên thấy như vậy. ",
  "dn9:41.6": "Các pháp nhiễm ô sẽ được đoạn trừ, các pháp thanh tịnh sẽ được tăng trưởng, và người ấy sẽ ngay trong hiện tại, tự mình với thắng trí chứng ngộ, thành tựu và an trú trong sự viên mãn và quảng đại của trí tuệ; và sẽ có hân hoan, hỷ, khinh an, chánh niệm, tỉnh giác, và đời sống an lạc. ",
  "dn9:42.1": "Này Poṭṭhapāda, đối với sự đạt được tự ngã vô sắc, ta cũng thuyết pháp để từ bỏ nó: ",
  "dn9:42.2": "‘để cho nơi các ông, khi thực hành đúng theo đó, các pháp nhiễm ô sẽ được đoạn trừ, các pháp thanh tịnh sẽ được tăng trưởng, và các ông sẽ ngay trong hiện tại, tự mình với thắng trí chứng ngộ, thành tựu và an trú trong sự viên mãn và quảng đại của trí tuệ.’ ",
  "dn9:42.3": "Nhưng này Poṭṭhapāda, có thể các ông nghĩ như vầy: ",
  "dn9:42.4": "‘Các pháp nhiễm ô sẽ được đoạn trừ, các pháp thanh tịnh sẽ được tăng trưởng, và người ấy sẽ ngay trong hiện tại, tự mình với thắng trí chứng ngộ, thành tựu và an trú trong sự viên mãn và quảng đại của trí tuệ; nhưng đời sống ấy hẳn là khổ.’ ",
  "dn9:42.5": "Này Poṭṭhapāda, không nên thấy như vậy. ",
  "dn9:42.6": "Các pháp nhiễm ô sẽ được đoạn trừ, các pháp thanh tịnh sẽ được tăng trưởng, và người ấy sẽ ngay trong hiện tại, tự mình với thắng trí chứng ngộ, thành tựu và an trú trong sự viên mãn và quảng đại của trí tuệ; và sẽ có hân hoan, hỷ, khinh an, chánh niệm, tỉnh giác, và đời sống an lạc. ",
  "dn9:43.1": "Này Poṭṭhapāda, nếu người khác hỏi chúng ta như vầy: ",
  "dn9:43.2": "‘Này hiền giả, sự đạt được tự ngã thô mà các vị thuyết pháp để từ bỏ là gì, để cho nơi các vị, khi thực hành đúng theo đó, các pháp nhiễm ô sẽ được đoạn trừ, các pháp thanh tịnh sẽ được tăng trưởng, và các vị sẽ ngay trong hiện tại, tự mình với thắng trí chứng ngộ, thành tựu và an trú trong sự viên mãn và quảng đại của trí tuệ?’ thì khi được hỏi như vậy, chúng ta sẽ trả lời như vầy: ",
  "dn9:43.3": "‘Này hiền giả, đây chính là sự đạt được tự ngã thô mà chúng tôi thuyết pháp để từ bỏ, để cho nơi các vị, khi thực hành đúng theo đó, các pháp nhiễm ô sẽ được đoạn trừ, các pháp thanh tịnh sẽ được tăng trưởng, và các vị sẽ ngay trong hiện tại, tự mình với thắng trí chứng ngộ, thành tựu và an trú trong sự viên mãn và quảng đại của trí tuệ.’ ",
  "dn9:44.1": "Này Poṭṭhapāda, nếu người khác hỏi chúng ta như vầy: ",
  "dn9:44.2": "‘Này hiền giả, sự đạt được tự ngã do ý tạo mà các vị thuyết pháp để từ bỏ là gì, để cho nơi các vị, khi thực hành đúng theo đó, các pháp nhiễm ô sẽ được đoạn trừ, các pháp thanh tịnh sẽ được tăng trưởng, và các vị sẽ ngay trong hiện tại, tự mình với thắng trí chứng ngộ, thành tựu và an trú trong sự viên mãn và quảng đại của trí tuệ?’ ",
  "dn9:44.3": "thì khi được hỏi như vậy, chúng ta sẽ trả lời như vầy: ",
  "dn9:44.4": "‘Này hiền giả, đây chính là sự đạt được tự ngã do ý tạo mà chúng tôi thuyết pháp để từ bỏ, để cho nơi các vị, khi thực hành đúng theo đó, các pháp nhiễm ô sẽ được đoạn trừ, các pháp thanh tịnh sẽ được tăng trưởng, và các vị sẽ ngay trong hiện tại, tự mình với thắng trí chứng ngộ, thành tựu và an trú trong sự viên mãn và quảng đại của trí tuệ.’ ",
  "dn9:45.1": "Này Poṭṭhapāda, nếu người khác hỏi chúng ta như vầy: ",
  "dn9:45.2": "‘Này hiền giả, sự đạt được tự ngã vô sắc mà các vị thuyết pháp để từ bỏ là gì, để cho nơi các vị, khi thực hành đúng theo đó, các pháp nhiễm ô sẽ được đoạn trừ, các pháp thanh tịnh sẽ được tăng trưởng, và các vị sẽ ngay trong hiện tại, tự mình với thắng trí chứng ngộ, thành tựu và an trú trong sự viên mãn và quảng đại của trí tuệ?’ ",
  "dn9:45.3": "thì khi được hỏi như vậy, chúng ta sẽ trả lời như vầy: ",
  "dn9:45.4": "‘Này hiền giả, đây chính là sự đạt được tự ngã vô sắc mà chúng tôi thuyết pháp để từ bỏ, để cho nơi các vị, khi thực hành đúng theo đó, các pháp nhiễm ô sẽ được đoạn trừ, các pháp thanh tịnh sẽ được tăng trưởng, và các vị sẽ ngay trong hiện tại, tự mình với thắng trí chứng ngộ, thành tựu và an trú trong sự viên mãn và quảng đại của trí tuệ.’ ",
  "dn9:45.5": "Ông nghĩ sao, này Poṭṭhapāda, ",
  "dn9:45.6": "trong trường hợp như vậy, lời nói ấy chẳng phải là có căn cứ sao?’",
  "dn9:45.7": "‘Thưa Thế Tôn, đúng vậy, trong trường hợp như vậy, lời nói ấy là có căn cứ.’ ",
  "dn9:46.1": "‘Ví như, này Poṭṭhapāda, có người làm một cái thang để leo lên lầu ngay dưới chính cái lầu ấy. ",
  "dn9:46.2": "Người ta có thể nói với người ấy như vầy: ",
  "dn9:46.3": "“Này anh kia, cái lầu mà anh làm thang để leo lên đó, anh có biết nó ở phương đông, hay phương nam, hay phương tây, hay phương bắc; cao, thấp hay vừa phải không?” ",
  "dn9:46.4": "Người ấy có thể đáp như vầy: ",
  "dn9:46.5": "“Này hiền giả, đây chính là cái lầu mà tôi làm thang để leo lên, ngay dưới chính cái lầu ấy.” ",
  "dn9:46.6": "Ông nghĩ sao, này Poṭṭhapāda, ",
  "dn9:46.7": "trong trường hợp như vậy, lời nói của người ấy chẳng phải là có căn cứ sao?’",
  "dn9:46.8": "‘Thưa Thế Tôn, đúng vậy, trong trường hợp như vậy, lời nói của người ấy là có căn cứ.’ ",
  "dn9:47.1": "‘Cũng vậy, này Poṭṭhapāda, nếu người khác hỏi chúng ta như vầy: ",
  "dn9:47.2": "“Này hiền giả, sự đạt được tự ngã thô là gì … ",
  "dn9:47.3": "sự đạt được tự ngã do ý tạo là gì … ",
  "dn9:47.4": "sự đạt được tự ngã vô sắc mà các vị thuyết pháp để từ bỏ là gì, để cho nơi các vị, khi thực hành đúng theo đó, các pháp nhiễm ô sẽ được đoạn trừ, các pháp thanh tịnh sẽ được tăng trưởng, và các vị sẽ ngay trong hiện tại, tự mình với thắng trí chứng ngộ, thành tựu và an trú trong sự viên mãn và quảng đại của trí tuệ?” ",
  "dn9:47.5": "thì khi được hỏi như vậy, chúng ta sẽ trả lời như vầy: ",
  "dn9:47.6": "“Này hiền giả, đây chính là sự đạt được tự ngã vô sắc mà chúng tôi thuyết pháp để từ bỏ, để cho nơi các vị, khi thực hành đúng theo đó, các pháp nhiễm ô sẽ được đoạn trừ, các pháp thanh tịnh sẽ được tăng trưởng, và các vị sẽ ngay trong hiện tại, tự mình với thắng trí chứng ngộ, thành tựu và an trú trong sự viên mãn và quảng đại của trí tuệ.” ",
  "dn9:47.7": "Ông nghĩ sao, này Poṭṭhapāda, trong trường hợp như vậy, lời nói ấy chẳng phải là có căn cứ sao?’",
  "dn9:47.8": "‘Thưa Thế Tôn, đúng vậy, trong trường hợp như vậy, lời nói ấy là có căn cứ.’ ",
  "dn9:48.1": "Khi được nói vậy, Citta Hatthisāriputta bạch Thế Tôn như sau: ",
  "dn9:48.2": "“Bạch Thế Tôn, vào lúc có sự đạt được tự ngã thô trọng, thì vào lúc ấy sự đạt được tự ngã do ý sanh là rỗng không, sự đạt được tự ngã vô sắc là rỗng không; ",
  "dn9:48.3": "chỉ có sự đạt được tự ngã thô trọng của vị ấy là chân thật vào lúc ấy. ",
  "dn9:48.4": "Bạch Thế Tôn, vào lúc có sự đạt được tự ngã do ý sanh, thì vào lúc ấy sự đạt được tự ngã thô trọng là rỗng không, sự đạt được tự ngã vô sắc là rỗng không; ",
  "dn9:48.5": "chỉ có sự đạt được tự ngã do ý sanh của vị ấy là chân thật vào lúc ấy. ",
  "dn9:48.6": "Bạch Thế Tôn, vào lúc có sự đạt được tự ngã vô sắc, thì vào lúc ấy sự đạt được tự ngã thô trọng là rỗng không, sự đạt được tự ngã do ý sanh là rỗng không; ",
  "dn9:48.7": "chỉ có sự đạt được tự ngã vô sắc của vị ấy là chân thật vào lúc ấy.” ",
  "dn9:49.1": "“Này Citta, vào lúc có sự đạt được tự ngã thô trọng, thì vào lúc ấy không được kể là sự đạt được tự ngã do ý sanh, cũng không được kể là sự đạt được tự ngã vô sắc; ",
  "dn9:49.2": "chỉ được kể là sự đạt được tự ngã thô trọng vào lúc ấy. ",
  "dn9:49.3": "Này Citta, vào lúc có sự đạt được tự ngã do ý sanh, thì vào lúc ấy không được kể là sự đạt được tự ngã thô trọng, cũng không được kể là sự đạt được tự ngã vô sắc; ",
  "dn9:49.4": "chỉ được kể là sự đạt được tự ngã do ý sanh vào lúc ấy. ",
  "dn9:49.5": "Này Citta, vào lúc có sự đạt được tự ngã vô sắc, thì vào lúc ấy không được kể là sự đạt được tự ngã thô trọng, cũng không được kể là sự đạt được tự ngã do ý sanh; ",
  "dn9:49.6": "chỉ được kể là sự đạt được tự ngã vô sắc vào lúc ấy. ",
  "dn9:49.7": "Này Citta, nếu người ta hỏi ông như vầy: ",
  "dn9:49.8": "‘Ông đã có mặt trong thời quá khứ, chứ không phải ông đã không có; ",
  "dn9:49.9": "ông sẽ có mặt trong thời vị lai, chứ không phải ông sẽ không có; ",
  "dn9:49.10": "ông hiện có mặt bây giờ, chứ không phải ông không có mặt’ ",
  "dn9:49.11": "Được hỏi như vậy, này Citta, ông sẽ trả lời thế nào?” ",
  "dn9:49.12": "“Bạch Thế Tôn, nếu người ta hỏi con như vầy: ",
  "dn9:49.13": "‘Ông đã có mặt trong thời quá khứ, chứ không phải ông đã không có; ",
  "dn9:49.14": "ông sẽ có mặt trong thời vị lai, chứ không phải ông sẽ không có; ",
  "dn9:49.15": "ông hiện có mặt bây giờ, chứ không phải ông không có mặt’ ",
  "dn9:49.16": "Được hỏi như vậy, bạch Thế Tôn, con sẽ trả lời như vầy: ",
  "dn9:49.17": "‘Tôi đã có mặt trong thời quá khứ, chứ không phải tôi đã không có; ",
  "dn9:49.18": "tôi sẽ có mặt trong thời vị lai, chứ không phải tôi sẽ không có; ",
  "dn9:49.19": "tôi hiện có mặt bây giờ, chứ không phải tôi không có mặt.’ ",
  "dn9:49.20": "Được hỏi như vậy, bạch Thế Tôn, con sẽ trả lời như thế.” ",
  "dn9:50.1": "“Nhưng này Citta, nếu người ta hỏi ông như vầy: ",
  "dn9:50.2": "‘Sự đạt được tự ngã quá khứ nào đã thuộc về ông, chỉ sự đạt được tự ngã ấy của ông là chân thật, còn vị lai là rỗng không, hiện tại là rỗng không? ",
  "dn9:50.3": "Sự đạt được tự ngã vị lai nào sẽ thuộc về ông, chỉ sự đạt được tự ngã ấy của ông là chân thật, còn quá khứ là rỗng không, hiện tại là rỗng không? ",
  "dn9:50.4": "Sự đạt được tự ngã hiện tại nào hiện thuộc về ông, chỉ sự đạt được tự ngã ấy của ông là chân thật, còn quá khứ là rỗng không, vị lai là rỗng không?’ ",
  "dn9:50.5": "Được hỏi như vậy, này Citta, ông sẽ trả lời thế nào?” ",
  "dn9:50.6": "“Nhưng bạch Thế Tôn, nếu người ta hỏi con như vầy: ",
  "dn9:50.7": "‘Sự đạt được tự ngã quá khứ nào đã thuộc về ông, chỉ sự đạt được tự ngã ấy của ông là chân thật, còn vị lai là rỗng không, hiện tại là rỗng không. ",
  "dn9:50.8": "Sự đạt được tự ngã vị lai nào sẽ thuộc về ông, chỉ sự đạt được tự ngã ấy của ông là chân thật, còn quá khứ là rỗng không, hiện tại là rỗng không. ",
  "dn9:50.9": "Sự đạt được tự ngã hiện tại nào hiện thuộc về ông, chỉ sự đạt được tự ngã ấy của ông là chân thật, còn quá khứ là rỗng không, vị lai là rỗng không.’ ",
  "dn9:50.10": "Được hỏi như vậy, bạch Thế Tôn, con sẽ trả lời như vầy: ",
  "dn9:50.11": "‘Sự đạt được tự ngã quá khứ nào đã thuộc về tôi, thì chính sự đạt được tự ngã ấy của tôi là chân thật vào lúc ấy, còn vị lai là rỗng không, hiện tại là rỗng không. ",
  "dn9:50.12": "Sự đạt được tự ngã vị lai nào sẽ thuộc về tôi, thì chính sự đạt được tự ngã ấy của tôi sẽ là chân thật vào lúc ấy, còn quá khứ là rỗng không, hiện tại là rỗng không. ",
  "dn9:50.13": "Sự đạt được tự ngã hiện tại nào hiện thuộc về tôi, thì chính sự đạt được tự ngã ấy của tôi là chân thật, còn quá khứ là rỗng không, vị lai là rỗng không.’ ",
  "dn9:50.14": "Được hỏi như vậy, bạch Thế Tôn, con sẽ trả lời như thế.” ",
  "dn9:51.1": "“Cũng vậy, này Citta, vào lúc có sự đạt được tự ngã thô trọng, thì vào lúc ấy không được kể là sự đạt được tự ngã do ý sanh, cũng không được kể là sự đạt được tự ngã vô sắc. ",
  "dn9:51.2": "Chỉ được kể là sự đạt được tự ngã thô trọng vào lúc ấy. ",
  "dn9:51.3": "Này Citta, vào lúc có sự đạt được tự ngã do ý sanh … ",
  "dn9:51.4": "này Citta, vào lúc có sự đạt được tự ngã vô sắc, thì vào lúc ấy không được kể là sự đạt được tự ngã thô trọng, cũng không được kể là sự đạt được tự ngã do ý sanh; ",
  "dn9:51.5": "chỉ được kể là sự đạt được tự ngã vô sắc vào lúc ấy. ",
  "dn9:52.1": "Ví như, này Citta, từ bò có sữa, từ sữa có sữa chua, từ sữa chua có bơ tươi, từ bơ tươi có bơ chín, từ bơ chín có tinh chất bơ. ",
  "dn9:52.2": "Vào lúc là sữa, thì vào lúc ấy không được kể là sữa chua, không được kể là bơ tươi, không được kể là bơ chín, không được kể là tinh chất bơ; ",
  "dn9:52.3": "chỉ được kể là sữa vào lúc ấy. ",
  "dn9:52.4": "Vào lúc là sữa chua … ",
  "dn9:52.5": "vào lúc là bơ tươi … ",
  "dn9:52.6": "vào lúc là bơ chín … ",
  "dn9:52.7": "vào lúc là tinh chất bơ, thì vào lúc ấy không được kể là sữa, không được kể là sữa chua, không được kể là bơ tươi, không được kể là bơ chín; ",
  "dn9:52.8": "chỉ được kể là tinh chất bơ vào lúc ấy. ",
  "dn9:53.1": "Cũng vậy, này Citta, vào lúc có sự đạt được tự ngã thô trọng … ",
  "dn9:53.2": "này Citta, vào lúc có sự đạt được tự ngã do ý sanh … ",
  "dn9:53.3": "này Citta, vào lúc có sự đạt được tự ngã vô sắc, thì vào lúc ấy không được kể là sự đạt được tự ngã thô trọng, cũng không được kể là sự đạt được tự ngã do ý sanh; ",
  "dn9:53.4": "chỉ được kể là sự đạt được tự ngã vô sắc vào lúc ấy. ",
  "dn9:53.5": "Này Citta, đó là những danh xưng thế gian, ngôn ngữ thế gian, cách nói thế gian, quy ước thế gian mà Như Lai dùng đến nhưng không chấp thủ.” ",
  "dn9:54.1": "Khi được nói vậy, du sĩ Poṭṭhapāda bạch Thế Tôn rằng: ",
  "dn9:54.2": "“Thật vi diệu, bạch Thế Tôn, thật vi diệu, bạch Thế Tôn. ",
  "dn9:54.3": "Ví như dựng đứng lại vật bị lật úp, mở ra vật bị che kín, chỉ đường cho người lạc lối, hay cầm đèn dầu trong bóng tối để những ai có mắt có thể thấy các sắc; cũng vậy, Chánh pháp đã được Thế Tôn trình bày bằng nhiều phương cách. ",
  "dn9:54.4": "Con xin quy y Thế Tôn, quy y Pháp và quy y Tăng chúng Tỳ-kheo. ",
  "dn9:54.5": "Mong Thế Tôn ghi nhận con là cư sĩ từ nay cho đến mạng chung đã quy y.” ",
  "dn9:55.0": "2.3. Citta Hatthisāriputta thọ cụ túc giới ",
  "dn9:55.1": "Rồi Citta Hatthisāriputta bạch Thế Tôn rằng: ",
  "dn9:55.2": "“Thật vi diệu, bạch Thế Tôn, thật vi diệu, bạch Thế Tôn. ",
  "dn9:55.3": "Ví như dựng đứng lại vật bị lật úp, mở ra vật bị che kín, chỉ đường cho người lạc lối, hay cầm đèn dầu trong bóng tối để những ai có mắt có thể thấy các sắc; cũng vậy, Chánh pháp đã được Thế Tôn trình bày bằng nhiều phương cách. ",
  "dn9:55.4": "Con xin quy y Thế Tôn, quy y Pháp và quy y Tăng chúng Tỳ-kheo. ",
  "dn9:55.5": "Bạch Thế Tôn, mong con được xuất gia trong sự hiện diện của Thế Tôn, mong được thọ cụ túc giới.” ",
  "dn9:56.1": "Citta Hatthisāriputta đã được xuất gia trong sự hiện diện của Thế Tôn, đã được thọ cụ túc giới. ",
  "dn9:56.2": "Không bao lâu sau khi thọ cụ túc giới, Tôn giả Citta Hatthisāriputta sống một mình, viễn ly, không phóng dật, nhiệt tâm, chuyên chú, chẳng bao lâu đã tự mình với thắng trí chứng ngộ, chứng đạt và an trú ngay trong hiện tại cứu cánh vô thượng của phạm hạnh, vì mục đích ấy mà các thiện nam tử chân chánh từ bỏ gia đình, sống không gia đình, xuất gia. ",
  "dn9:56.3": "Vị ấy đã biết rõ: ‘Sanh đã tận, phạm hạnh đã thành, việc cần làm đã làm xong, không còn trở lui trạng thái này nữa.’ ",
  "dn9:56.4": "Và Tôn giả Citta Hatthisāriputta đã trở thành một vị A-la-hán. ",
  "dn9:56.5": "Kinh Poṭṭhapāda thứ chín đã hoàn tất. "
}
